from pycocoevalcap.cider.cider import Cider
from pycocoevalcap.tokenizer.ptbtokenizer import PTBTokenizer

def compute_cider(generated, references):
    gts = {}
    res = {}
    for img_id in generated:
        if img_id not in references:
            continue
        gts[img_id] = [{"caption": r} for r in references[img_id]]
        res[img_id] = [{"caption": generated[img_id]}]

    tokenizer = PTBTokenizer()
    gts_tok = tokenizer.tokenize(gts)
    res_tok = tokenizer.tokenize(res)

    scorer = Cider()
    score, scores = scorer.compute_score(gts_tok, res_tok)
    return score * 100

print("CIDEr function ready.")

"""this is an early test I did with full 3600 images for English. The results after this are done with 1000 images only"""

