results["en"] = {"cider": cider, "n": len(generated), "time": 0}
print(f"English CIDEr: {cider:.1f}  (Paper: 80.2)")

import time

# ── choose according to the languages u wanna test ──
# EVAL_LANGS = CORE_LANGS          # speed test: just en, es, hi, zh
# EVAL_LANGS = CORE_LANGS + L5_LANGS  # middle: core + low-resource
EVAL_LANGS = ["en", "es", "hi", "zh", "ar", "ja", "sw", "te"]
MAX_SAMPLES = 1000

results = {}

for lang in EVAL_LANGS:
    print(f"\n{'='*60}")
    print(f"Evaluating: {LANG_NAMES.get(lang, lang)} ({lang})")
    print(f"{'='*60}")

    t0 = time.time()

    # 1. Dataset download
    ds = load_xm3600_split(lang, max_samples=MAX_SAMPLES)
    print(f"  Images: {len(ds)}")

    # 2. Reference dict is made
    references = {}
    for sample in ds:
        img_id = str(sample["image_id"])
        refs = sample["captions"]
        if not isinstance(refs, list):
            refs = [refs]
        references[img_id] = refs

    # 3. Caption made
    generated = generate_captions_for_dataset(ds, lang)

    # 4. CIDEr calculate
    cider = compute_cider(generated, references)

    elapsed = time.time() - t0
    results[lang] = {"cider": cider, "n": len(generated), "time": elapsed}

    # sample show
    sample_id = list(generated.keys())[0]
    print(f"  CIDEr: {cider:.1f}")
    print(f"  Sample gen: '{generated[sample_id]}'")
    print(f"  Sample ref: '{references[sample_id][0]}'")
    print(f"  Time: {elapsed:.0f}s")

print("\nDONE!")

"""japanese and chinese are written without any space between words, so i made a new approach:"""

import spacy

try:
    nlp_zh = spacy.load("zh_core_web_sm")
except:
    nlp_zh = None
try:
    nlp_ja = spacy.load("ja_core_news_sm")
except:
    nlp_ja = None

SPACY_TOKENIZERS = {"zh": nlp_zh, "ja": nlp_ja}

def spacy_tokenize(text, lang):
    nlp = SPACY_TOKENIZERS.get(lang)
    if nlp:
        return " ".join([tok.text for tok in nlp(text)])
    return text

def compute_cider(generated, references, lang="en"):
    gts = {}
    res = {}
    for img_id in generated:
        if img_id not in references:
            continue
        gen_cap = generated[img_id]
        ref_caps = references[img_id]
        if lang in ["zh", "ja", "th"]:
            gen_cap = spacy_tokenize(gen_cap, lang)
            ref_caps = [spacy_tokenize(r, lang) for r in ref_caps]
        gts[img_id] = [{"caption": r} for r in ref_caps]
        res[img_id] = [{"caption": gen_cap}]

    tokenizer = PTBTokenizer()
    gts_tok = tokenizer.tokenize(gts)
    res_tok = tokenizer.tokenize(res)

    scorer = Cider()
    score, scores = scorer.compute_score(gts_tok, res_tok)
    return score * 100

print("CIDEr updated with CJK tokenization.")

for lang in ["zh", "ja"]:
    print(f"Re-evaluating {lang}...")
    ds = load_xm3600_split(lang, max_samples=1000)
    references = {}
    for sample in ds:
        references[str(sample["image_id"])] = sample["captions"]
    generated = generate_captions_for_dataset(ds, lang)
    cider = compute_cider(generated, references, lang=lang)
    results[lang]["cider"] = cider
    print(f"  {lang} CIDEr: {cider:.1f}")



